local iter = coroutine.wrap(function()
  for _, item in ipairs(wf.vars.items) do
    coroutine.yield(item)
  end
end)

return {
  first = iter(),
  second = iter(),
  third = iter()
}

local co = coroutine.create(function()
  local name = coroutine.yield("awaiting_name")
  return "hello " .. tostring(name)
end)

local _, first = coroutine.resume(co)
local _, second = coroutine.resume(co, "Lua")

return {
  first = first,
  second = second
}

